$hotels = \App\Models\Hotel::all();
$index = 0;

foreach ($hotels as $hotel) {
    if (isset($HOTEL_IMAGE_MAP[$hotel->title])) {
        $hotel->image = $HOTEL_IMAGE_MAP[$hotel->title];
    } else {
        $hotel->image = $generic_luxury[$index % count($generic_luxury)];
        $index++;
    }
    $hotel->save();
}
echo "All hotels updated with beautiful mixed images.\n";
